package com.cognizant.springtesting; import java.util.NoSuchElementException;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;@ControllerAdvice public class GlobalExceptionHandler {@ExceptionHandler(NoSuchElementException.class) public ResponseEntity<String> handleNoSuchElementException(NoSuchElementException exception){return ResponseEntity.status(HttpStatus.NOT_FOUND).body("User not found");}}
